#!/usr/bin/env bash
# Reset profiling environment between runs.
# Run from the project root: bash profiling/reset.sh
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
ROOT_DIR="$(dirname "$SCRIPT_DIR")"

# Restore state baseline
cp "$SCRIPT_DIR/profiling.state.json" "$ROOT_DIR/.crma-load.state.json"
echo "State reset from profiling/profiling.state.json"

# Remove CSV output files generated by file-target entries
rm -f \
  "$ROOT_DIR/AllLightningPageView.csv" \
  "$ROOT_DIR/ProdLightningPageView.csv" \
  "$ROOT_DIR/XrmruUser.csv"
echo "CSV output files removed"

echo "Ready for next run."
